Here's a complete implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // must reset or spinner stays
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = CurrentItem
        });

        CurrentItem = null;   // clear selection so the same item can be re-selected
    }
}
```

### Key binding relationships

| XAML property | ViewModel property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool, TwoWay) | Shows/hides spinner; **set to `false`** when done |
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload |
| `CollectionView.ItemsSource` | `Items` (`ObservableCollection<T>`) | Auto-updates UI on add/remove |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Tracks selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires navigation; reset `CurrentItem` to `null` after |

### Important notes

- **Use `ObservableCollection<T>`**, not `List<T>` — otherwise the UI won't update.
- **Reset `IsRefreshing = false`** in a `finally` block so the spinner always stops.
- **Reset `CurrentItem = null`** after navigation so the user can tap the same item again.
- **Update collections on the UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Uses MVVM Community Toolkit (`[ObservableProperty]`, `[RelayCommand]`) for boilerplate-free bindings.
